import akka.actor.{Actor, ActorRef, ActorSystem, Props}
import java.util.UUID
import scala.concurrent.duration._

sealed trait AccountMessage
case class Deposit(amount: BigDecimal, transactionId: String = UUID.randomUUID().toString) extends AccountMessage
case class Withdraw(amount: BigDecimal, transactionId: String = UUID.randomUUID().toString) extends AccountMessage
case class GetBalance(replyTo: ActorRef) extends AccountMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionResult(transactionId: String, success: Boolean, message: String, newBalance: BigDecimal)

class SecureAccountActor(initialBalance: BigDecimal) extends Actor {
  private var balance: BigDecimal = initialBalance
  private val processedTransactions = scala.collection.mutable.Set[String]()
  private val maxTransactionHistorySize = 10000

  def receive: Receive = {
    case Deposit(amount, transactionId) =>
      if (processedTransactions.contains(transactionId)) {
        sender() ! TransactionResult(transactionId, false, "Duplicate transaction", balance)
      } else if (amount <= 0) {
        sender() ! TransactionResult(transactionId, false, "Invalid deposit amount", balance)
      } else if (amount > BigDecimal("999999999.99")) {
        sender() ! TransactionResult(transactionId, false, "Deposit amount exceeds maximum allowed", balance)
      } else {
        val newBalance = balance + amount
        if (newBalance > BigDecimal("9999999999.99")) {
          sender() ! TransactionResult(transactionId, false, "Account balance would exceed maximum limit", balance)
        } else {
          balance = newBalance
          addProcessedTransaction(transactionId)
          sender() ! TransactionResult(transactionId, true, "Deposit successful", balance)
        }
      }

    case Withdraw(amount, transactionId) =>
      if (processedTransactions.contains(transactionId)) {
        sender() ! TransactionResult(transactionId, false, "Duplicate transaction", balance)
      } else if (amount <= 0) {
        sender() ! TransactionResult(transactionId, false, "Invalid withdrawal amount", balance)
      } else if (amount > balance) {
        sender() ! TransactionResult(transactionId, false, "Insufficient funds", balance)
      } else if (amount > BigDecimal("999999999.99")) {
        sender() ! TransactionResult(transactionId, false, "Withdrawal amount exceeds maximum allowed", balance)
      } else {
        balance = balance - amount
        addProcessedTransaction(transactionId)
        sender() ! TransactionResult(transactionId, true, "Withdrawal successful", balance)
      }

    case GetBalance(replyTo) =>
      replyTo ! BalanceResponse(balance)
  }

  private def addProcessedTransaction(transactionId: String): Unit = {
    if (processedTransactions.size >= maxTransactionHistorySize) {
      val toRemove = processedTransactions.take(maxTransactionHistorySize / 2)
      processedTransactions --= toRemove
    }
    processedTransactions += transactionId
  }
}

object SecureAccountActor {
  def props(initialBalance: BigDecimal): Props = Props(new SecureAccountActor(initialBalance))
}

object AccountSystem {
  def createAccountActor(system: ActorSystem, accountId: String, initialBalance: BigDecimal): ActorRef = {
    system.actorOf(SecureAccountActor.props(initialBalance), s"account-$accountId")
  }
}